SELECT DISTINCT FROM biz_notice n INNER JOIN biz_notice_scope ns ON n.id = ns.notice_id WHERE n.deleted = 0 AND n.status = 'PUBLISHED'
AND n.title LIKE CONCAT('%', #{query.keyword}, '%')
AND n.notice_type = #{query.noticeType}
AND ( ns.scope_type = 'ALL' OR ns.scope_ref_id = #{userOrgId} OR #{ancestorPath} LIKE CONCAT('%/', ns.scope_ref_id, '/%') ) ORDER BY n.top_flag DESC, n.publish_time DESC, n.id DESC LIMIT #{size} OFFSET #{offset}
